#!/usr/bin/env python3
"""Extract information from agent benchmark papers."""
import pdfplumber
import json
import re

papers_info = {
    "api-bank": {
        "file": "/workspace/papers/api-bank.pdf",
        "benchmark_name": "API-Bank",
    },
    "acebench": {
        "file": "/workspace/papers/acebench.pdf",
        "benchmark_name": "ACEBench",
    },
    "tau-bench": {
        "file": "/workspace/papers/tau-bench.pdf",
        "benchmark_name": "τ-bench",
    },
    "tau2-bench": {
        "file": "/workspace/papers/tau2-bench.pdf",
        "benchmark_name": "τ²-bench",
    },
    "workarena": {
        "file": "/workspace/papers/workarena.pdf",
        "benchmark_name": "WorkArena",
    },
    "workarena++": {
        "file": "/workspace/papers/workarena++.pdf",
        "benchmark_name": "WorkArena++",
    },
    "itbench": {
        "file": "/workspace/papers/itbench.pdf",
        "benchmark_name": "ITBench",
    },
    "workbench": {
        "file": "/workspace/papers/workbench.pdf",
        "benchmark_name": "WorkBench",
    },
    "theagentcompany": {
        "file": "/workspace/papers/theagentcompany.pdf",
        "benchmark_name": "TheAgentCompany",
    },
    "crmarena": {
        "file": "/workspace/papers/crmarena.pdf",
        "benchmark_name": "CRMArena",
    },
    "crmarena-pro": {
        "file": "/workspace/papers/crmarena-pro.pdf",
        "benchmark_name": "CRMArena-Pro",
    },
}

def extract_text_from_pdf(pdf_path):
    """Extract all text from a PDF file."""
    try:
        with pdfplumber.open(pdf_path) as pdf:
            text = ""
            for page in pdf.pages:
                try:
                    page_text = page.extract_text()
                    if page_text:
                        text += page_text + "\n"
                except Exception as e:
                    print(f"Error extracting page: {e}")
            return text
    except Exception as e:
        print(f"Error reading {pdf_path}: {e}")
        return ""

def main():
    results = {}
    for key, info in papers_info.items():
        print(f"Processing {key}...")
        text = extract_text_from_pdf(info["file"])
        # Save raw text for analysis
        results[key] = {
            "benchmark_name": info["benchmark_name"],
            "text_length": len(text),
            "first_5000_chars": text[:5000],
            "full_text": text
        }
        print(f"  Extracted {len(text)} characters")

    # Save to file
    with open("/workspace/papers_extracted.json", "w") as f:
        json.dump(results, f, indent=2)
    print("\nExtraction complete. Saved to /workspace/papers_extracted.json")

if __name__ == "__main__":
    main()
